WITH checks(check_name,ok) AS(VALUES('cancel_rpc_exists',to_regprocedure('public.cancel_mistaken_shipments_v1(uuid[],text)') IS NOT NULL),('single_core_exists',to_regprocedure('public.undo_shipment_core_20260722(uuid)') IS NOT NULL),('bulk_core_exists',to_regprocedure('public.undo_shipments_v1_core_20260722(uuid[])') IS NOT NULL),('audit_table_rls',COALESCE((SELECT c.relrowsecurity FROM pg_class c JOIN pg_namespace n ON n.oid=c.relnamespace WHERE n.nspname='public' AND c.relname='shipment_cancellation_audit'),false)),('cancel_rpc_checks_today',COALESCE(position('shipment_date<>v_today' IN pg_get_functiondef(to_regprocedure('public.cancel_mistaken_shipments_v1(uuid[],text)')))>0,false)),('old_single_path_blocked',COALESCE(position('app.allow_mistaken_shipment_cancel' IN pg_get_functiondef(to_regprocedure('public.undo_shipment(uuid)')))>0,false)),('old_bulk_path_blocked',COALESCE(position('app.allow_mistaken_shipment_cancel' IN pg_get_functiondef(to_regprocedure('public.undo_shipments_v1(uuid[])')))>0,false)),('authenticated_can_cancel',COALESCE(has_function_privilege('authenticated',to_regprocedure('public.cancel_mistaken_shipments_v1(uuid[],text)'),'EXECUTE'),false)),('anon_cannot_cancel',NOT COALESCE(has_function_privilege('anon',to_regprocedure('public.cancel_mistaken_shipments_v1(uuid[],text)'),'EXECUTE'),false)),('authenticated_cannot_call_single_core',NOT COALESCE(has_function_privilege('authenticated',to_regprocedure('public.undo_shipment_core_20260722(uuid)'),'EXECUTE'),false)),('authenticated_cannot_call_bulk_core',NOT COALESCE(has_function_privilege('authenticated',to_regprocedure('public.undo_shipments_v1_core_20260722(uuid[])'),'EXECUTE'),false))) SELECT check_name FROM checks WHERE NOT ok ORDER BY check_name;
